(()=>{"use strict";document.addEventListener("DOMContentLoaded",()=>{const e=()=>{if(window.innerWidth<580){const e=document.querySelector(".mobile-btn"),o=document.querySelector(".mobile-block"),t=document.querySelector(".mobile-menu__close");e.onclick=()=>{o.classList.add("active"),document.body.style.overflow="hidden"},t.onclick=()=>{document.body.style.overflow="",o.classList.remove("active")}}};e(),window.addEventListener("resize",e)})})();